+    return executeProviderOperation({
+      capability,
+      config,
+      provider,
+      providerConfig: providerConfig as AnyProvider,
+      ctx,
+      signal,
+      options,
+      urls,
+    });
+  }
+
+  if (capability === "answer") {
+    return executeProviderOperation({
+      capability,
+      config,
+      provider,
+      providerConfig: providerConfig as AnyProvider,
+      ctx,
+      signal,
+      options,
+      query,
+    });
+  }
+
+  return executeProviderOperation({
+    capability,
+    config,
+    provider,
+    providerConfig: providerConfig as AnyProvider,
+    ctx,
+    signal,
+    options,
+    input,
+  });
