+function extractSearchResultFromRenderedContent(
+  renderedContent: string | undefined,
+): { title?: string; url?: string } {
+  const [result] = extractSearchResultsFromHtml(renderedContent);
+  if (!result) {
+    return {};
+  }
+  return result;
+}
